// ★各カットの画像ファイル名とモーションプロンプトを設定してください
// imageFile: ComfyUIのinputフォルダにアップロード済みの画像ファイル名
// motion: そのカットの動きの説明（LTX-2.3に渡すプロンプト）
// ★各カットのモーションプロンプトを設定してください
// imageFileはFLUX.2ワークフローが自動生成したcut_01.png〜を使用
const cuts = [
  {
    motion: 'The mother mallard duck struggles under the net, wings flapping frantically. Heavy snow falls. Static camera.'
  },
  {
    motion: 'A hand reaches into frame and lifts the net. The duck pauses, then slowly waddles free. Static camera.'
  }
];
return [{ json: { cuts, index: 0 } }];

const promptId = $input.first().json.prompt_id;
if (!promptId) throw new Error('prompt_id取得失敗: ' + JSON.stringify($input.first().json));
const { cuts, index } = $('Build Video Workflow').first().json;
return [{ json: { cuts, index, prompt_id: promptId } }];

const history = $input.first().json;
const state = $('Save Submit').first().json;
const { prompt_id, cuts, index } = state;

const entry = history[prompt_id];
if (!entry?.status?.completed) {
  return [{ json: { ...state, done: false } }];
}

return [{ json: { ...state, done: true } }];
